#include <stdio.h>
int myAtoi(char * s) {
    int sign = 1;
    long long num = 0;
    while (*s == ' ') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;
    while (*s >= '0' && *s <= '9') {
        num = num * 10 + (*s - '0');
        if (num > 2147483647 && sign == 1) return 2147483647;
        if (num > 2147483648 && sign == -1) return -2147483648;
        s++;
    }
    return sign * num;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

const int INT_MIN_VAL = -2147483648;
const int INT_MAX_VAL = 2147483647;

int myAtoi(string s) {
    int i = 0;
    while (i < s.size() && s[i] == ' ') i++;
    int sign = 1;
    if (i < s.size() && (s[i] == '+' || s[i] == '-')) {
        sign = (s[i] == '-') ? -1 : 1;
        i++;
    }
    long long num = 0;
    while (i < s.size() && isdigit(s[i])) {
        num = num * 10 + (s[i] - '0');
        if (sign * num <= INT_MIN_VAL) return INT_MIN_VAL;
        if (sign * num >= INT_MAX_VAL) return INT_MAX_VAL;
        i++;
    }
    return sign * num;
}

