public class Solution {
    public int myAtoi(String s) {
        int sign = 1;
        long num = 0;
        s = s.trim();
        if (s.isEmpty()) return 0;
        if (s.charAt(0) == '-') { sign = -1; s = s.substring(1); }
        else if (s.charAt(0) == '+') s = s.substring(1);
        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) {
                num = num * 10 + (c - '0');
                if (num > 2147483647 && sign == 1) return 2147483647;
                if (num > 2147483648 && sign == -1) return -2147483648;
            } else break;
        }
        return (int) (sign * num);
    }
}

code.Python3:
def myAtoi(s: str) -> int:
    s = s.lstrip()
    if not s: return 0
    sign = -1 if s[0] == '-' else 1
    if s[0] in ['-', '+']:
        s = s[1:]
    num = 0
    for c in s:
        if c.isdigit():
            num = num * 10 + int(c)
            if num > 2**31 - 1 and sign == 1: return 2**31 - 1
            if num > 2**31 and sign == -1: return -2**31
        else:
            break
    return sign * num

